    18→// MockStorage for testing API handler
    19→type MockAPIStorage struct {
    20→	data map[string][]byte
    21→}
    22→
    23→func NewMockAPIStorage() *MockAPIStorage {
    24→	return &MockAPIStorage{
    25→		data: make(map[string][]byte),
    26→	}
    27→}
    28→
    29→func (m *MockAPIStorage) Get(ctx context.Context, key string) (io.ReadCloser, error) {
    30→	data, exists := m.data[key]
    31→	if !exists {
    32→		return nil, fmt.Errorf("not found")
    33→	}
    34→	return io.NopCloser(bytes.NewReader(data)), nil
    35→}
    36→
    37→func (m *MockAPIStorage) Put(ctx context.Context, key string, reader io.Reader, opts ...storage.PutOption) error {
    38→	data, err := io.ReadAll(reader)
    39→	if err != nil {
    40→		return err
    41→	}
    42→	m.data[key] = data
    43→	return nil
    44→}
    45→
    46→func (m *MockAPIStorage) Delete(ctx context.Context, key string) error {
    47→	delete(m.data, key)
    48→	return nil
    49→}
    50→
    51→func (m *MockAPIStorage) Exists(ctx context.Context, key string) (bool, error) {
    52→	_, exists := m.data[key]
    53→	return exists, nil
    54→}
    55→
    56→func (m *MockAPIStorage) List(ctx context.Context, opts storage.ListOptions) ([]storage.Object, error) {
    57→	var objects []storage.Object
    58→	for key := range m.data {
    59→		if strings.HasPrefix(key, opts.Prefix) {
    60→			objects = append(objects, storage.Object{
    61→				Key:  key,
    62→				Size: int64(len(m.data[key])),
    63→			})
    64→		}
    65→	}
    66→
    67→	if opts.MaxKeys > 0 && len(objects) > opts.MaxKeys {
    68→		objects = objects[:opts.MaxKeys]
    69→	}
    70→
    71→	return objects, nil
    72→}
    73→
    74→func (m *MockAPIStorage) DeleteBatch(ctx context.Context, keys []string) error {
    75→	for _, key := range keys {
    76→		delete(m.data, key)
    77→	}
    78→	return nil
    79→}
    80→
    81→func (m *MockAPIStorage) Head(ctx context.Context, key string) (*storage.Object, error) {
    82→	data, exists := m.data[key]
    83→	if !exists {
    84→		return nil, fmt.Errorf("not found")
    85→	}
    86→	return &storage.Object{
    87→		Key:  key,
    88→		Size: int64(len(data)),
    89→	}, nil
    90→}
    91→
    92→func (m *MockAPIStorage) UpdateMetadata(ctx context.Context, key string, metadata map[string]string) error {
    93→	return nil
    94→}
    95→
    96→func (m *MockAPIStorage) Copy(ctx context.Context, src, dst string) error {
    97→	data, exists := m.data[src]
    98→	if !exists {
    99→		return fmt.Errorf("source not found")
   100→	}
   101→	m.data[dst] = make([]byte, len(data))
   102→	copy(m.data[dst], data)
   103→	return nil
   104→}
   105→
   106→func (m *MockAPIStorage) Move(ctx context.Context, src, dst string) error {
   107→	if err := m.Copy(ctx, src, dst); err != nil {
